# fix-project-categories-sidebar-and-client.ps1
# Root causes:
# 1&2. AdminSidebar.tsx had a literal duplicate 'Project Categories' entry -> rendered twice, both active.
# 3&4. Prisma Client running in `next dev` is stale (generated before visible/featured/description_*
#      were added, or generate failed earlier from the file-lock issue) -> those columns are never
#      selected/sent, so every category reads as hidden and PATCH rejects description_en as unknown.
# Fix: dedupe sidebar + force a clean Prisma Client regen (stop dev server before running this).
$ErrorActionPreference = 'Stop'
Write-Host "Stop your `npm run dev` terminal before running this script." -ForegroundColor Yellow

Write-Host "Writing src\components\admin\AdminSidebar.tsx"
$dir = Split-Path -Parent "src\components\admin\AdminSidebar.tsx"
if ($dir -and !(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
$b64AdminSidebar = @"

"@
[System.IO.File]::WriteAllBytes("src\components\admin\AdminSidebar.tsx", [System.Convert]::FromBase64String($b64AdminSidebar))

Write-Host "Regenerating Prisma Client..." -ForegroundColor Cyan
if (Test-Path node_modules\.prisma) { Remove-Item -Recurse -Force node_modules\.prisma }
npx prisma generate
npx prisma db push
Write-Host "Done. Now run: npm run dev" -ForegroundColor Green